 1	import type { FC } from 'react';
 2	import SectionHeading from 'src/components/headers/SectionHeading';
 3	import MapsSection from 'src/storageMaps/details/MapsSection';
 4	import { useForkliftTranslation } from 'src/utils/i18n';
 5	
 6	import LoadingSuspend from '@components/LoadingSuspend';
 7	import { StorageMapModelGroupVersionKind, type V1beta1StorageMap } from '@kubev2v/types';
 8	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 9	import { Flex, PageSection } from '@patternfly/react-core';
10	
11	import { ConditionsSection } from '../../components/ConditionsSection/ConditionsSection';
12	import DetailsSection from '../../components/DetailsSection/DetailsSection';
13	import { ProvidersSection } from '../../components/ProvidersSection/ProvidersSection';
14	
15	type StorageMapDetailsTabProps = {
16	  name: string;
17	  namespace: string;
18	};
19	
20	export const StorageMapDetailsTab: FC<StorageMapDetailsTabProps> = ({ name, namespace }) => {
21	  const { t } = useForkliftTranslation();
22	
23	  const [obj, loaded, loadError] = useK8sWatchResource<V1beta1StorageMap>({
24	    groupVersionKind: StorageMapModelGroupVersionKind,
25	    isList: false,
26	    name,
27	    namespace,
28	    namespaced: true,
29	  });
30	
31	  return (
32	    <LoadingSuspend obj={obj} loaded={loaded} loadError={loadError}>
33	      <PageSection variant="light" className="forklift-page-section--details">
34	        <SectionHeading text={t('Storage map details')} />
35	        <DetailsSection obj={obj} />
36	      </PageSection>
37	
38	      <PageSection variant="light" className="forklift-page-section">
39	        <SectionHeading text={t('Providers')} />
40	        <ProvidersSection obj={obj} />
41	      </PageSection>
42	
43	      <PageSection variant="light" className="forklift-page-section">
44	        <Flex direction={{ default: 'column' }} spaceItems={{ default: 'spaceItemsLg' }}>
45	          <SectionHeading text={t('Map')} />
46	          <MapsSection storageMap={obj} />
47	        </Flex>
48	      </PageSection>
49	
50	      <PageSection variant="light" className="forklift-page-section">
51	        <SectionHeading text={t('Conditions')} />
52	        <ConditionsSection conditions={obj?.status?.conditions ?? []} />
53	      </PageSection>
54	    </LoadingSuspend>
55	  );
56	};

